import React, { useState, useEffect } from "react";
import { useParams, useLocation, Link } from "react-router-dom";

import Header from "../components/common/Header";
import Navbar from "../components/common/Navbar";
import Footer from "../components/common/Footer";
import ProductCard from "../components/product/ProductCard";
import { productAPI, categoryAPI } from "../api";

const ProductList = () => {
  const { slug } = useParams();
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);

  const searchQuery = queryParams.get("q");
  const categoryQuery = queryParams.get("category");

  const [sortOption, setSortOption] = useState("alpha-asc");

  const [products, setProducts] = useState([]);
  const [categoryName, setCategoryName] = useState("Tất cả sản phẩm");
  const [category, setCategory] = useState(null);

  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalProducts, setTotalProducts] = useState(0);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [priceFilter, setPriceFilter] = useState(null);
  const [flowerFilter, setFlowerFilter] = useState(null);
  const [occasionFilter, setOccasionFilter] = useState(null);

  useEffect(() => {
    setCurrentPage(1);
  }, [slug, searchQuery, categoryQuery]);

  useEffect(() => {
    fetchProducts();
  }, [slug, searchQuery, categoryQuery, currentPage]);

  // 🚀 FETCH PRODUCTS
  const fetchProducts = async () => {
    try {
      setLoading(true);
      setError("");

      let response;

      // Search / Filter
      if (searchQuery || categoryQuery) {
        // Tìm kiếm với từ khóa và/hoặc danh mục
        console.log(`Calling search API with keyword: ${searchQuery}, category: ${categoryQuery}`);
        
        response = await productAPI.searchProducts({
          keyword: searchQuery || "",
          category: categoryQuery || "all",
          page: currentPage,
        });

        setProducts(response.data.products || []);
        setTotalPages(response.data.pages || 1);
        setTotalProducts(response.data.total || 0);
        setCategoryName(`Kết quả tìm kiếm`);
      }

      // Category slug
      else if (slug) {
        response = await categoryAPI.getProductsByCategory(slug, currentPage);
        setProducts(response.data.products || []);
        setCategory(response.data.category || null);
        setCategoryName(response.data.category?.name || "");
        setTotalPages(response.data.pages || 1);
        setTotalProducts(response.data.total || 0);
      }

      // All products
      else {
        response = await productAPI.searchProducts({
          keyword: searchQuery || "",
          category: categoryQuery || "all",
          price: priceFilter,
          flower: flowerFilter,
          occasion: occasionFilter,
          page: currentPage,
        });

        setProducts(response.data.products || []);
        setCategoryName("Tất cả sản phẩm");
        setTotalPages(response.data.pages || 1);
        setTotalProducts(response.data.total || 0);
      }

    } catch (err) {
      console.error("❌ Lỗi tải sản phẩm:", err);
      setError("Không thể tải sản phẩm. Vui lòng thử lại.");
    }

    setLoading(false);
  };

  // Sorting
  const sortedProducts = [...products].sort((a, b) => {
    switch (sortOption) {
      case "alpha-asc":
        return a.name.localeCompare(b.name, "vi");
      case "alpha-desc":
        return b.name.localeCompare(a.name, "vi");
      case "price-asc":
        return (a.discountPrice || a.price) - (b.discountPrice || b.price);
      case "price-desc":
        return (b.discountPrice || b.price) - (a.discountPrice || a.price);
      case "newest":
        return new Date(b.createdAt) - new Date(a.createdAt);
      default:
        return 0;
    }
  });

  // ==========================
  //        RETURN UI
  // ==========================
  return (
  <div className="flex flex-col min-h-screen bg-white">
    <Header />
    <Navbar />

    <main className="max-w-7xl mx-auto px-6 py-8 flex-1">

      {/* Breadcrumb
      <nav className="text-sm text-gray-500 mb-4">
        <Link to="/" className="hover:text-[#e06c7f]">Trang chủ</Link>
        <span className="mx-1">›</span>
        <span className="text-gray-700">Sản phẩm</span>
      </nav> */}

      {/* Page Title */}
      <h1 className="text-3xl font-bold text-[#2c2c2c] mb-4">
        {categoryName}
      </h1>

      {/* Summary + Sort */}
      <div className="
        bg-white border border-pink-100 shadow-sm rounded-xl 
        px-4 py-3 mb-6 
        flex flex-col md:flex-row justify-between md:items-center 
        gap-4
      ">
        <p className="text-gray-600 text-sm">
          Hiển thị <b>{products.length}</b> / {totalProducts} sản phẩm
        </p>

        <div className="flex items-center gap-2">
          <span className="text-sm text-gray-600 whitespace-nowrap">
            Sắp xếp:
          </span>

          <select
            value={sortOption}
            onChange={(e) => setSortOption(e.target.value)}
            className="
              border border-pink-300 rounded-lg px-3 py-2 text-sm 
              bg-white outline-none cursor-pointer
              hover:border-[#e06c7f] transition
            "
          >
            <option value="alpha-asc">Tên: A → Z</option>
            <option value="alpha-desc">Tên: Z → A</option>
            <option value="price-asc">Giá: thấp → cao</option>
            <option value="price-desc">Giá: cao → thấp</option>
            <option value="newest">Mới nhất</option>
          </select>
        </div>
      </div>

      {/* ======================== */}
{/* LAYOUT: SIDEBAR + GRID  */}
{/* ======================== */}

<div className="flex flex-col md:flex-row gap-8">

  {/* Sidebar */}
  <aside className="hidden md:block w-[260px] flex-shrink-0 
    bg-white border border-pink-100 rounded-xl p-4 shadow-sm h-fit">
    
    <h3 className="font-semibold mb-3 text-[#2c2c2c]">Bộ lọc</h3>

    {/* Giá */}
    <div className="mb-4">
      <p className="text-sm font-medium mb-2 text-gray-700">Giá</p>
      <ul className="space-y-1 text-sm text-gray-600">
        <li><button className="hover:text-[#e06c7f]">Dưới 200.000đ</button></li>
        <li><button className="hover:text-[#e06c7f]">200.000đ – 400.000đ</button></li>
        <li><button className="hover:text-[#e06c7f]">Trên 400.000đ</button></li>
      </ul>
    </div>

    {/* Loại hoa */}
    <div className="mb-4">
      <p className="text-sm font-medium mb-2 text-gray-700">Loại hoa</p>
      <ul className="space-y-1 text-sm text-gray-600">
        <li><button className="hover:text-[#e06c7f]">Hoa hồng</button></li>
        <li><button className="hover:text-[#e06c7f]">Hoa baby</button></li>
        <li><button className="hover:text-[#e06c7f]">Hướng dương</button></li>
      </ul>
    </div>

    {/* Dịp tặng */}
    <div className="mb-4">
      <p className="text-sm font-medium mb-2 text-gray-700">Dịp tặng</p>
      <ul className="space-y-1 text-sm text-gray-600">
        <li><button className="hover:text-[#e06c7f]">Sinh nhật</button></li>
        <li><button className="hover:text-[#e06c7f]">Tốt nghiệp</button></li>
        <li><button className="hover:text-[#e06c7f]">Khai trương</button></li>
      </ul>
    </div>

  </aside>

  {/* Product Grid */}
  <div className="flex-1">
    {loading ? (
      <p className="text-center py-10 text-gray-500">Đang tải sản phẩm...</p>
    ) : sortedProducts.length === 0 ? (
      <p className="text-center py-10 text-gray-500">Không có sản phẩm nào.</p>
    ) : (
      <div className="grid gap-6 
        grid-cols-2 sm:grid-cols-2 md:grid-cols-3 xl:grid-cols-4">
        {sortedProducts.map((product) => (
          <ProductCard key={product._id} product={product} />
        ))}
      </div>
    )}
  </div>

</div>


      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex justify-center mt-10">
          <div className="flex gap-2">
            {[...Array(totalPages)].map((_, index) => (
              <button
                key={index}
                onClick={() => setCurrentPage(index + 1)}
                className={`
                  px-4 py-2 rounded-lg border transition
                  ${
                    currentPage === index + 1
                      ? "bg-[#e06c7f] border-[#e06c7f] text-white"
                      : "bg-white border-gray-300 text-gray-700 hover:border-[#e06c7f]"
                  }
                `}
              >
                {index + 1}
              </button>
            ))}
          </div>
        </div>
      )}

    </main>

    <Footer />
  </div>
);

};

export default ProductList;
